import store from '@/store'
import Vue from 'vue'
import VueRouter from 'vue-router'

// 如果必须使用绝对路径，将反斜杠替换为正斜杠
import HomeView from 'C:/Users/38390/Desktop/drone/vue/vue/src/views/Home.vue'



Vue.use(VueRouter)


const routes = [
  {
    path: '/',
    component: () => import(/* webpackChunkName: "about" */ '../views/Manage.vue'),
    redirect:"/home",
    children: [
      {
        path: 'home',name:"无人机管理中心",component: () => import(/* webpackChunkName: "about" */'../views/Home.vue')
      },
      {
        path: 'drone',name:"无人机",component: () => import(/* webpackChunkName: "about" */'../views/drone.vue')
      },
      {
        path: 'task',name:"无人机任务",component: () => import(/* webpackChunkName: "about" */'../views/task.vue')
      },
      {
        path: 'Photography',name:"现场视频",component: () => import(/* webpackChunkName: "about" */'../views/Photography.vue')
      },
      {
        path: 'recognition',name:"识别记录",component: () => import(/* webpackChunkName: "about" */'../views/recognition.vue')
      },
    ]
  },
  {
    path: '/about',
    name: 'about',
    // route level code-splitting
    // this generates a separate chunk (about.[hash].js) for this route
    // which is lazy-loaded when the route is visited.
    component: () => import(/* webpackChunkName: "about" */ '../views/AboutView.vue')
  },
]

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes
})
//防止重复点击路由报错
const originalPush = VueRouter.prototype.push
VueRouter.prototype.push = function push(location) {
  return originalPush.call(this, location).catch(err => err)
}

// 确保目标路由的meta.requiresAuth被正确识别
router.beforeEach((to, from, next) => {
  console.log('目标路由：', to.path, '需要登录：', to.matched.some(r => r.meta.requiresAuth));
  if (to.matched.some(record => record.meta.requiresAuth)) {
    const token = localStorage.getItem('token');
    console.log('当前token：', token);
    if (!token) {
      next('/login'); // 无token跳登录
    } else {
      next();
    }
  } else {
    next();
  }
});

export default router
